def _make_action(
    name="test_action",
    group="test",
    input_type=InputType.ANALOG,
    trigger_mode=EventTriggerMode.SCALED,
    deadband=0.05,
    scale=1.0,
    inversion=False,
    slew_rate=0.0,
    threshold=0.5,
):
    """Create a minimal ActionDefinition for testing."""
    return ActionDefinition(
        name=name,
        group=group,
        description="test",
        input_type=input_type,
        trigger_mode=trigger_mode,
        deadband=deadband,
        scale=scale,
        inversion=inversion,
        slew_rate=slew_rate,
        threshold=threshold,
        extra={},
    )


# --- ManagedAnalog param validation ---

class TestAnalogParamValidation:

    def test_valid_params_list(self):
        """All expected params are in the valid set."""
        assert "deadband" in ManagedAnalog._PARAM_TYPES
        assert "inversion" in ManagedAnalog._PARAM_TYPES
        assert "scale" in ManagedAnalog._PARAM_TYPES
        assert "slew_rate" in ManagedAnalog._PARAM_TYPES

    def test_invalid_param_returns_false(self):
        """mapParamToNtPath rejects unknown param names."""
        action = _make_action()
        analog = ManagedAnalog(action, lambda: 0.0)
        result = analog.mapParamToNtPath("/test/path", "not_a_real_param")
        assert result is False

    def test_mapped_params_empty_initially(self):
        """No custom mappings on a fresh ManagedAnalog."""
        action = _make_action()
        analog = ManagedAnalog(action, lambda: 0.0)
        assert len(analog.mapped_params) == 0

    def test_unmap_nonexistent_returns_false(self):
        """Unmapping a param that isn't mapped returns False."""
        action = _make_action()
        analog = ManagedAnalog(action, lambda: 0.0)
        assert analog.unmap("scale") is False

    def test_clear_maps_on_empty(self):
        """clearMaps on empty mapping dict is a no-op."""
        action = _make_action()
        analog = ManagedAnalog(action, lambda: 0.0)
        analog.clearMaps()
        assert len(analog.mapped_params) == 0


